        status = etree.SubElement(response, '{%s}Status' % SAMLP_NS)
        status_code = etree.SubElement(status, '{%s}StatusCode' % SAMLP_NS)
        status_code.set('Value', 'urn:oasis:names:tc:SAML:2.0:status:Success')

