        assertion = etree.SubElement(
            response,
            '{%s}Assertion' % SAML_NS,
            nsmap=NSMAP,
            attrib={
                'ID': assertion_id,
                'Version': '2.0',
                'IssueInstant': issue_instant,
            }
        )

        # Assertion Issuer
        assertion_issuer = etree.SubElement(assertion, '{%s}Issuer' % SAML_NS)
        assertion_issuer.text = self._entity_id

