def require_https(f):
    """Decorator to enforce HTTPS."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check X-Forwarded-Proto for reverse proxy setups
        proto = request.headers.get('X-Forwarded-Proto', request.scheme)
        if proto != 'https':
            logger.warning("Non-HTTPS request rejected from %s", request.remote_addr)
            abort(403, description="HTTPS required")
        return f(*args, **kwargs)
    return decorated_function


def sanitize_input(value: str, max_length: int = 1024) -> str:
    """Sanitize user input."""
    if value is None:
        return None
    # Truncate to max length
    value = value[:max_length]
    # Remove null bytes
    value = value.replace('\x00', '')
    return value


def validate_username(username: str) -> bool:
    """Validate username format."""
    if not username:
        return False
    if len(username) > 256:
        return False
    # Allow alphanumeric, dots, underscores, hyphens, and @ for email-style usernames
    return bool(re.match(r'^[a-zA-Z0-9._@-]+$', username))


@app.before_request
def security_headers():
    """Add security headers to all responses."""
    pass


@app.after_request
def add_security_headers(response):
    """Add security headers."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Content-Security-Policy'] = "default-src 'self'; script-src 'none'; style-src 'self' 'unsafe-inline'"
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response


