@app.route('/saml/sso', methods=['GET', 'POST'])
@require_https
def sso():
    """SAML Single Sign-On endpoint."""
    saml_request = None
    relay_state = None

    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest')
        relay_state = request.args.get('RelayState')
    elif request.method == 'POST':
        saml_request = request.form.get('SAMLRequest')
        relay_state = request.form.get('RelayState')

    if not saml_request:
        logger.warning("SSO request without SAMLRequest from %s", request.remote_addr)
        abort(400, description="Missing SAMLRequest parameter")

    # Sanitize relay state
    relay_state = sanitize_input(relay_state, max_length=2048)

    # Parse and validate the AuthnRequest
    try:
        authn_request = AuthnRequestParser.parse(saml_request)
    except ValueError as e:
        logger.warning("Invalid AuthnRequest from %s: %s", request.remote_addr, str(e))
        abort(400, description="Invalid SAML AuthnRequest")

    # Validate the SP is in our allowlist
    sp_entity_id = authn_request.get('issuer')
    sp_config = sp_registry.get_provider(sp_entity_id)
    if not sp_config:
        logger.warning("Unknown SP entity ID: %s from %s", sp_entity_id, request.remote_addr)
        abort(403, description="Unknown Service Provider")

    # Validate ACS URL if provided
    acs_url = authn_request.get('assertion_consumer_service_url')
    if acs_url:
        if not sp_registry.is_allowed_acs_url(sp_entity_id, acs_url):
            logger.warning(
                "Invalid ACS URL %s for SP %s from %s",
                acs_url, sp_entity_id, request.remote_addr
            )
            abort(403, description="Invalid Assertion Consumer Service URL")
    else:
        acs_url = sp_config['acs_url']

    # Validate ACS URL is HTTPS
    parsed_acs = urlparse(acs_url)
    if parsed_acs.scheme != 'https':
        logger.warning("Non-HTTPS ACS URL rejected: %s", acs_url)
        abort(403, description="ACS URL must use HTTPS")

    # Store request details in session
    request_id = secrets.token_hex(16)
    session['saml_request'] = {
        'id': request_id,
        'authn_request_id': authn_request['id'],
        'sp_entity_id': sp_entity_id,
        'acs_url': acs_url,
        'name_id_format': authn_request.get('name_id_format', sp_config['allowed_name_id_format']),
        'relay_state': relay_state,
        'timestamp': time.time(),
    }

    # Check if user is already authenticated
    if 'authenticated_user' in session:
        # Verify session hasn't expired
        auth_time = session.get('auth_time', 0)
        if time.time() - auth_time < 28800:  # 8 hour session max
            return _build_and_send_response(session['authenticated_user'])

    # Show login form
    csrf_token = CSRFProtection.generate_token()
    return render_template_string(
        LOGIN_TEMPLATE,
        csrf_token=csrf_token,
        saml_request_id=request_id,
        sp_entity_id=sp_entity_id,
        error=None,
    )


@app.route('/saml/login', methods=['POST'])
@require_https
def login():
    """Handle login form submission."""
    # Validate CSRF token
    csrf_token = request.form.get('csrf_token', '')
    if not CSRFProtection.validate_token(csrf_token):
        logger.warning("CSRF validation failed from %s", request.remote_addr)
        abort(403, description="Invalid CSRF token")

    # Validate SAML request is in session
    saml_req = session.get('saml_request')
    if not saml_req:
        logger.warning("Login attempt without SAML request from %s", request.remote_addr)
        abort(400, description="No pending SAML request")

    # Check request age (prevent replay of old requests)
    request_age = time.time() - saml_req.get('timestamp', 0)
    if request_age > 600:  # 10 minutes max
        session.pop('saml_request', None)
        logger.warning("Expired SAML request from %s", request.remote_addr)
        abort(400, description="SAML request has expired")

    # Validate request ID matches
    submitted_request_id = sanitize_input(request.form.get('saml_request_id', ''))
    if not hmac.compare_digest(submitted_request_id or '', saml_req['id']):
        logger.warning("SAML request ID mismatch from %s", request.remote_addr)
        abort(400, description="Invalid request")

    # Get and validate credentials
    username = sanitize_input(request.form.get('username', ''), max_length=256)
    password = request.form.get('password', '')

    if not validate_username(username):
        csrf_token = CSRFProtection.generate_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            csrf_token=csrf_token,
            saml_request_id=saml_req['id'],
            sp_entity_id=saml_req['sp_entity_id'],
            error='Invalid username format.',
        ), 400

    if not password or len(password) > 256:
        csrf_token = CSRFProtection.generate_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            csrf_token=csrf_token,
            saml_request_id=saml_req['id'],
            sp_entity_id=saml_req['sp_entity_id'],
            error='Invalid password.',
        ), 400

    # Check rate limiting
    rate_key = f"{request.remote_addr}:{username}"
    if rate_limiter.is_rate_limited(rate_key):
        logger.warning("Rate limited login attempt for %s from %s", username, request.remote_addr)
        csrf_token = CSRFProtection.generate_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            csrf_token=csrf_token,
            saml_request_id=saml_req['id'],
            sp_entity_id=saml_req['sp_entity_id'],
            error='Too many login attempts. Please try again later.',
        ), 429

    # Record the attempt
    rate_limiter.record_attempt(rate_key)

    # Verify credentials
    if not user_store.verify_password(username, password):
        logger.info("Failed login attempt for user from %s", request.remote_addr)
        csrf_token = CSRFProtection.generate_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            csrf_token=csrf_token,
            saml_request_id=saml_req['id'],
            sp_entity_id=saml_req['sp_entity_id'],
            error='Invalid username or password.',
        ), 401

    # Authentication successful
    logger.info("Successful authentication from %s", request.remote_addr)

    # Store authenticated user in session
    session['authenticated_user'] = username
    session['auth_time'] = time.time()

    # Regenerate session ID to prevent session fixation
    session.modified = True

    return _build_and_send_response(username)


def _build_and_send_response(username: str):
    """Build SAML response and send to SP."""
    saml_req = session.get('saml_request')
    if not saml_req:
        abort(400, description="No pending SAML request")

    # Get user attributes
    user_attrs = user_store.get_user_attributes(username)
    if not user_attrs:
        logger.error("User attributes not found for authenticated user")
        abort(500, description="Internal error")

    # Determine NameID based on format
    name_id_format = saml_req.get('name_id_format', 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress')

    if name_id_format == 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress':
        name_id = user_attrs['email']
    elif name_id_format == 'urn:oasis:names:tc:SAML:2.0:nameid-format:persistent':
        # Generate a persistent, opaque identifier
        name_id = hashlib.sha256(
            f"{username}:{saml_req['sp_entity_id']}:{SAML_IDP_ENTITY_ID}".encode()
        ).hexdigest()
    elif name_id_format == 'urn:oasis:names:tc:SAML:2.0:nameid-format:transient':
        name_id = secrets.token_hex(20)
    else:
        name_id = user_attrs['email']
        name_id_format = 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress'

    # Build SAML attributes
    attributes = {
        'email': user_attrs['email'],
        'displayName': user_attrs['display_name'],
        'groups': user_attrs['groups'],
    }

    # Build signed SAML response
    try:
        saml_response = saml_builder.build_response(
            sp_entity_id=saml_req['sp_entity_id'],
            acs_url=saml_req['acs_url'],
            name_id=name_id,
            name_id_format=name_id_format,
            attributes=attributes,
            in_response_to=saml_req.get('authn_request_id'),
        )
    except Exception as e:
        logger.error("Failed to build SAML response: %s", str(e))
        abort(500, description="Failed to generate SAML response")

    # Clean up the SAML request from session (one-time use)
    session.pop('saml_request', None)

    # Send response via POST binding
    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=saml_req['acs_url'],
        saml_response=saml_response,
        relay_state=saml_req.get('relay_state'),
    )


@app.route('/saml/logout', methods=['POST'])
@require_https
def logout():
    """Handle logout."""
    # Validate CSRF
    csrf_token = request.form.get('csrf_token', '')
    if not CSRFProtection.validate_token(csrf_token):
        abort(403, description="Invalid CSRF token")

    # Clear session
    session.clear()
    logger.info("User logged out from %s", request.remote_addr)
    return redirect('/')


